// Forward declarations for pack file support
static char* read_pack_object_by_sha(GitRepository* repo, const char* sha,
                                      int* out_type, size_t* out_size);

static bool wcs_ends_with(const wchar_t* str, const wchar_t* suffix) {
    size_t slen = wcslen(str);
    size_t sflen = wcslen(suffix);
    if (sflen > slen) return false;
    return wcscmp(str + slen - sflen, suffix) == 0;
}

// packed_refs_lookup_sha / resolve_ref_sha live in git_objects.cpp (shared).

// Remove a single line from a packed-refs file whose ref-token equals full_ref.
// The packed-refs format is: "<40-char sha> <refname>\n" per line, with optional
// "^<sha>" peeled-tag lines and "#" comments. Returns true if a matching line
// was found and the file was rewritten; false otherwise.
//
// CRITICAL: Must load the *entire* file (mmap), never a fixed-size read_file buffer.
// Truncating before rewrite would delete every ref past the buffer boundary.
static bool packed_refs_remove_line(const wchar_t* packed_refs_path, const char* full_ref) {
    if (!packed_refs_path || !full_ref || !file_exists(packed_refs_path)) return false;

    MemoryMap* map = mmap_open(packed_refs_path);
    if (!map || !map->data || map->size == 0) {
        mmap_close(map);
        return false;
    }

    // Copy full contents then unmap so write_file_atomic can replace the file.
    size_t bytes_read = map->size;
    char* content = new (std::nothrow) char[bytes_read + 1];
    if (!content) {
        mmap_close(map);
        return false;
    }
    memcpy(content, map->data, bytes_read);
    content[bytes_read] = '\0';
    mmap_close(map);

    size_t full_ref_len = strlen(full_ref);
    bool rewrote = false;
    char* line_start = content;
    while (*line_start) {
        char* line_end = line_start;
        while (*line_end && *line_end != '\n' && *line_end != '\r') line_end++;
        char* line_eol = line_end;
        while (*line_eol == '\n' || *line_eol == '\r') line_eol++;

        char saved = *line_end;
        *line_end = '\0';
        bool match = false;
        if (line_start[0] != '#' && line_start[0] != '^') {
            char* space = strchr(line_start, ' ');
            if (space) {
                size_t token_len = (size_t)(line_end - (space + 1));
                match = token_len == full_ref_len &&
                        strncmp(space + 1, full_ref, full_ref_len) == 0;
            }
        }
        *line_end = saved;

        if (match) {
            // Drop an immediately following peeled-tag line (^sha) if present.
            char* remove_end = line_eol;
            if (*remove_end == '^') {
                while (*remove_end && *remove_end != '\n' && *remove_end != '\r') remove_end++;
                while (*remove_end == '\n' || *remove_end == '\r') remove_end++;
            }

            size_t removed = (size_t)(remove_end - line_start);
            size_t new_size = bytes_read - removed;
            char* new_content = new (std::nothrow) char[new_size + 1];
            if (new_content) {
                size_t prefix_len = (size_t)(line_start - content);
                memcpy(new_content, content, prefix_len);
                memcpy(new_content + prefix_len, remove_end, bytes_read - (size_t)(remove_end - content));
                new_content[new_size] = '\0';
                rewrote = write_file_atomic(packed_refs_path, new_content, new_size);
                delete[] new_content;
            }
            break;
        }
        line_start = line_eol;
    }

    delete[] content;
    return rewrote;
}

// Check if a directory is a git repository
bool git_is_repository(const wchar_t* path) {
    wchar_t git_dir[Git::MAX_PATH_LEN];
    make_path(git_dir, Git::MAX_PATH_LEN, path, L".git");

    // Check for .git directory
    if (dir_exists(git_dir)) {
        // Verify it has HEAD file
        wchar_t head_path[Git::MAX_PATH_LEN];
        make_path(head_path, Git::MAX_PATH_LEN, git_dir, L"HEAD");
        return file_exists(head_path);
    }

    // Check for .git file (worktree or submodule)
    if (file_exists(git_dir)) {
        return true;
    }

    return false;
}

